using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public sealed class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public sealed class EvaluationResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public sealed class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _classLabels;

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResponse TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset use cross-validation to get meaningful metrics
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Train the final model on all data
        _model = pipeline.Fit(dataView);
        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
        BuildPredictionEngine(dataView);

        // Aggregate cross-validation metrics
        var avgMetrics = new EvaluationResponse
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            PerClassMetrics = BuildPerClassMetrics(cvResults)
        };

        return avgMetrics;
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model is not trained. Call /api/tickets/train first.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        if (_classLabels is not null)
        {
            for (var i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
            {
                confidence[_classLabels[i]] = prediction.Score[i];
            }
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public void LoadModel()
    {
        if (!File.Exists(_modelPath))
            return;

        _model = _mlContext.Model.Load(_modelPath, out var schema);
        var emptyData = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
        BuildPredictionEngine(emptyData);
    }

    private void BuildPredictionEngine(IDataView dataView)
    {
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract class labels from the Label column's key-type metadata
        var transformedData = _model!.Transform(dataView);
        var labelColumn = transformedData.Schema["Label"];
        if (labelColumn.Type is Microsoft.ML.Data.KeyDataViewType)
        {
            var keyValues = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
            labelColumn.GetKeyValues(ref keyValues);
            _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
        }
    }

    private static PerClassMetric[] BuildPerClassMetrics(
        IReadOnlyList<Microsoft.ML.TrainCatalogBase.CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
    {
        // Aggregate per-class precision/recall across folds
        var first = cvResults[0].Metrics.PerClassLogLoss;
        var metrics = new PerClassMetric[first.Count];
        for (var i = 0; i < first.Count; i++)
        {
            var precisions = cvResults.Select(r =>
                i < r.Metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? r.Metrics.ConfusionMatrix.PerClassPrecision[i] : 0).ToList();
            var recalls = cvResults.Select(r =>
                i < r.Metrics.ConfusionMatrix.PerClassRecall.Count
                    ? r.Metrics.ConfusionMatrix.PerClassRecall[i] : 0).ToList();

            var avgPrecision = precisions.Average();
            var avgRecall = recalls.Average();
            var f1 = avgPrecision + avgRecall > 0
                ? 2 * avgPrecision * avgRecall / (avgPrecision + avgRecall)
                : 0;

            metrics[i] = new PerClassMetric
            {
                Class = $"Class_{i}",
                Precision = avgPrecision,
                Recall = avgRecall,
                F1Score = f1
            };
        }
        return metrics;
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketClassifierController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains the model on the CSV data and returns cross-validated evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var metrics = _classifier.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model is not trained. POST to /api/tickets/train first." });

        var prediction = _classifier.Predict(request);
        return Ok(prediction);
    }
}

